def on_update(doc, method):
    # Vérifie si un document avancement existe déjà pour ce client
    if not frappe.db.exists("avancement", {"entreprise": doc.name}):
        # Crée un nouveau document avancement
        avancement = frappe.get_doc({
            "doctype": "avancement",
            "entreprise": doc.name,
            "etape": "Formation"
        })
        
        # Insère le document dans la base de données
        avancement.insert(ignore_permissions=True)
